import React, { useState } from 'react';
import api from '../api/api';

const RiskForm = ({ profile, fetchProfile }) => {
    const [formData, setFormData] = useState({
        family_history: 0, // 0=No, 1=Yes
        sleep_time: 7.0,
        junk_food_freq: 1
    });
    const [result, setResult] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const handleChange = (e) => {
        const { name, value, type, checked } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? (checked ? 1 : 0) : (type === 'number' ? parseFloat(value) : parseInt(value))
        }));
        setError('');
    };

    const handleSubmit = async (e) => {
        e.preventDefault(); 
        setLoading(true);
        setResult(null);
        setError('');

        // 1. Prepare payload by combining profile data and risk factors
        const payload = {
            bmi: profile.bmi, 
            age: profile.age,
            gender: profile.gender === 'male' ? 0 : 1, 
            activity_level: profile.activityLevel,
            
            family_history: formData.family_history,
            sleep_time: formData.sleep_time,
            junk_food_freq: formData.junk_food_freq
        };

        // 2. Call the backend API
        try {
            const response = await api.post('/risk/predict', payload);
            setResult(response.data.result);
            fetchProfile(); // Triggers parent (Dashboard) to fetch updated profile with new risk score
        } catch (err) {
            console.error('Risk prediction failed:', err.response?.data);
            setError(err.response?.data?.message || 'Prediction service is unavailable (Port 5000 down?)');
        } finally {
            setLoading(false);
        }
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-4 text-sm">
            
            {/* Family History Checkbox */}
            <div className="flex justify-between items-center bg-[#2D333B] p-3 rounded-lg border border-[#333]">
                <label htmlFor="family_history" className="text-gray-300">Family History of Obesity/Diabetes?</label>
                <input 
                    type="checkbox" 
                    name="family_history" 
                    id="family_history"
                    checked={formData.family_history === 1} 
                    onChange={handleChange} 
                    className="form-checkbox h-4 w-4 text-red-600 bg-transparent border-red-600" 
                />
            </div>
            
            {/* Sleep Time Input */}
            <div>
                <label htmlFor="sleep_time" className="block text-xs font-medium text-gray-400 mb-1">Average Sleep (Hours)</label>
                <input 
                    type="number" 
                    name="sleep_time" 
                    id="sleep_time"
                    placeholder="7.5" 
                    value={formData.sleep_time || ''} 
                    onChange={handleChange} 
                    step="0.5" 
                    required 
                    min="4" 
                    max="12" 
                    className="input" 
                />
            </div>
            
            {/* Junk Food Frequency Select */}
            <div>
                <label htmlFor="junk_food_freq" className="block text-xs font-medium text-gray-400 mb-1">Junk Food Consumption</label>
                <select name="junk_food_freq" id="junk_food_freq" value={formData.junk_food_freq} onChange={handleChange} className="select">
                    <option value={0}>Rarely (Once a month or less)</option>
                    <option value={1}>Weekly (1-2 times per week)</option>
                    <option value={2}>Daily (3+ times per week)</option>
                </select>
            </div>

            <button 
                type="submit" 
                disabled={loading} 
                className={`w-full p-3 rounded font-semibold shadow-md btn-risk`} // Using new btn-risk class
            >
                {loading ? 'Analyzing...' : 'Predict Health Risk'}
            </button>
            {error && <p className="text-red-400 mt-2 text-center">{error}</p>}

            {/* Display Results (Enhanced) */}
            {result && (
                <div className="mt-4 p-4 border border-gray-600 rounded-lg shadow-md bg-[#1E1E1E]">
                    <h4 className="text-xl font-bold mb-3 text-center text-accent-blue">Diagnosis Output</h4>
                    
                    {/* Status Indicator */}
                    <div className="text-center mb-4">
                        <p className="text-sm text-gray-400">Predicted Obesity Risk Level:</p>
                        <p className={`text-3xl font-extrabold tracking-wide 
                            ${result.obesity_risk === 'High' ? 'text-red-400' : 
                              result.obesity_risk === 'Medium' ? 'text-orange-400' : 
                              'text-ai-green'}`}>
                            {result.obesity_risk}
                        </p>
                    </div>

                    {/* Probability Breakdown */}
                    <div className="space-y-2">
                        <p className="font-semibold text-gray-400 border-b border-[#333] pb-1">Probability Breakdown:</p>
                        {Object.entries(result.probabilities).map(([riskLevel, percentage]) => (
                            <div key={riskLevel}>
                                <div className="flex justify-between text-sm">
                                    <span className="font-medium">{riskLevel} Risk</span>
                                    <span className="font-bold">{percentage}%</span>
                                </div>
                                
                                {/* Simple Progress Bar Mockup */}
                                <div className="w-full bg-gray-600 rounded-full h-2">
                                    <div 
                                        className={`h-2 rounded-full 
                                            ${riskLevel === 'High' ? 'bg-red-500' : 
                                              riskLevel === 'Medium' ? 'bg-orange-400' : 
                                              'bg-ai-green'}`} 
                                        style={{ width: `${percentage}%` }}
                                    ></div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </form>
    );
};

export default RiskForm;
